// src/components/Navbar.js
import React from 'react';
import { Link, useLocation } from 'react-router-dom';

const Navbar = () => {
  const location = useLocation();

  const menuItems = [
    { path: '/cars', label: 'Car', icon: '🚗' },
    { path: '/packages', label: 'Package', icon: '📦' },
    { path: '/service-packages', label: 'ServicePackage', icon: '🔧' },
    { path: '/payments', label: 'Payment', icon: '💰' },
    { path: '/reports', label: 'Reports', icon: '📊' },
  ];

  const isActive = (path) => {
    return location.pathname === path;
  };

  return (
    <nav className="bg-blue-700 text-white shadow-lg">
      <div className="container mx-auto px-4">
        <div className="flex justify-between items-center">
          <div className="flex items-center space-x-2 py-3">
            <span className="text-2xl">🚗💧</span>
            <span className="font-bold text-xl">SmartPark CWSMS</span>
          </div>
          <div className="flex space-x-1">
            {menuItems.map((item) => (
              <Link
                key={item.path}
                to={item.path}
                className={`px-4 py-3 rounded-lg transition-colors ${
                  isActive(item.path)
                    ? 'bg-blue-800 text-white'
                    : 'hover:bg-blue-600'
                }`}
              >
                <span className="mr-2">{item.icon}</span>
                {item.label}
              </Link>
            ))}
            <button
              onClick={() => {
                if (window.confirm('Are you sure you want to logout?')) {
                  window.location.href = '/';
                }
              }}
              className="px-4 py-3 rounded-lg hover:bg-red-600 transition-colors"
            >
              <span className="mr-2">🚪</span>
              Logout
            </button>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
